{

	nc=read(),cnt=read(),memset(dist,0x3f,sizeof(dist));

	for(register int i=0;i<cnt;i++)

	{

		x=read(),y=read(),z=read();

		ed[tot++]=(Edge){x,y,z};

		dist[x]=min(dist[x],z+1),dist[y]=min(dist[y],z+2);

	}

	update(),update();

	for(register int i=0;i<=nc;i++)

	{

		ed[tot++]=(Edge){i,(i+1)%nc,dist[i]};

	}

	printf("%lld",Kruskal());

}

